class NotificationEngine {
    static push(settings, notification) {
        if (!settings.notifications)
            settings.notifications = [];
        const entry = Object.assign(Object.assign({}, notification), { id: `notif_${Date.now()}_${Math.random().toString(36).slice(2, 6)}`, timestamp: new Date().toISOString(), read: false });
        settings.notifications.unshift(entry);
        if (settings.notifications.length > this.MAX_NOTIFICATIONS) {
            settings.notifications = settings.notifications.slice(0, this.MAX_NOTIFICATIONS);
        }
    }
    static markAllRead(settings) {
        if (!settings.notifications)
            return;
        settings.notifications.forEach(n => n.read = true);
    }
    static getUnreadCount(settings) {
        if (!settings.notifications)
            return 0;
        return settings.notifications.filter(n => !n.read).length;
    }
    static clear(settings) {
        settings.notifications = [];
    }
    static getRecent(settings, count = 15) {
        if (!settings.notifications)
            return [];
        return settings.notifications.slice(0, count);
    }
}
NotificationEngine.MAX_NOTIFICATIONS = 50;

